  ('p10', 'hooded-baby-towel-rabbit-grey', 'Hooded Baby Towel Rabbit Grey', 'Summerville organic', 'Baby & barsel', 'Økologisk babyhåndklæde med kanin-detalje i grå.', 87.96, 207.97, 2, '600879', 'https://cdn.faire.com/fastly/95f5cd5ac72e9298312585ebc8eab2306fdb06cc4f0e3b614205c600dadb8358.jpeg', true, ARRAY['Barsel','Baby gave'], 'box', 'live'),
  ('p11', 'franse-roze-klei', 'Franse Roze Klei', 'More', 'Naturlig beauty', '100% naturlig fransk rosa ler til wellness-æsker.', 49.58, 118.91, 2, '7442956129115', 'https://cdn.faire.com/fastly/4c3ce9eb94878f5e25df6f9e40ddf14abd1bd592dff1df26a3d1021086d66d6a.jpeg', true, ARRAY['Wellness','Rolig weekend'], 'jar', 'live'),
