  ('p15', 'rosehip-olie', 'Rosehip olie', 'More', 'Naturlig beauty', 'Økologisk og koldpresset rosehip olie.', 71.27, 171.09, 2, '8720299095168', 'https://cdn.faire.com/fastly/0ae6cc5fc64666b88bd818d984c3c92702695f39d2d69b520ce0f0b2ffa164cd.jpeg', true, ARRAY['Wellness','Ny mor'], 'bottle', 'live'),
  ('p16', 'jojoba-olie', 'Jojoba Olie', 'More', 'Naturlig beauty', 'Økologisk og koldpresset jojobaolie.', 76.26, 186.00, 2, '8720299095137', 'https://cdn.faire.com/fastly/9433451c7afbdc5e0a362368282f6decc233b05183e8f693f0402e1ae1ded286.jpeg', true, ARRAY['Wellness','Rolig weekend'], 'bottle', 'live')
